import React, { useState, useEffect } from 'react';
import './MainContent.css';
import './sidebar'; // Certifique-se de que a sidebar esteja corretamente importada

const MainContent = () => {
  const [message, setMessage] = useState('');
  const [sidebarOpen, setSidebarOpen] = useState(false); // Estado para controlar o menu lateral

  useEffect(() => {
    fetch('/api/reports')
      .then(response => {
        if (!response.ok) {
          throw new Error('Network response was not ok');
        }
        return response.json();
      })
      .then(data => setMessage(data.message))
      .catch(error => console.error('Error fetching reports:', error));
  }, []);

  // Função para alternar a exibição da sidebar
  const toggleSidebar = () => {
    setSidebarOpen(!sidebarOpen); // Alterna entre abrir e fechar a sidebar
  };

  // Função para exibir o dropdown
  const handleDropdownClick = (option) => {
    if (option === 'deleteAll') {
      // Função para excluir todos os relatórios
      console.log('Excluir todos os relatórios');
    } else if (option === 'configureDeletion') {
      // Função para configurar exclusão
      console.log('Configurar exclusão');
    }
  };

  return (
    <div className={`main-container ${sidebarOpen ? 'sidebar-open' : ''}`}>
      {/* Nome da página à esquerda da Sidebar */}
      <div className="sidebar-title">
        <h1>Relatórios</h1>
        {/* Botão de menu estilo hambúrguer */}
        <button className="hamburger-menu" onClick={toggleSidebar}>
          &#9776; {/* Ícone estilo hambúrguer */}
        </button>
      </div>

      <div className="main-content">
        {/* Título "Gestão" e dropdown de 3 pontinhos no canto direito */}
        <div className="header">
          <h2>Gestão</h2>
          <div className="dropdown">
            <button className="dropdown-button">⋮</button>
            <div className="dropdown-content">
              <ul>
                <li onClick={() => handleDropdownClick('deleteAll')}>Excluir todos os relatórios</li>
                <li onClick={() => handleDropdownClick('configureDeletion')}>Configurar exclusão</li>
              </ul>
            </div>
          </div>
        </div>

        {/* Pranchetas e mensagem de "sem relatórios" */}
        <div className="report-content">
          <div className="clipboard">
            <img src="/path/to/clipboard1.png" alt="Prancheta 1" />
            <img src="/path/to/clipboard2.png" alt="Prancheta 2" />
          </div>
          <p>{message || 'Você não possui relatórios gerados de gestão'}</p>
        </div>
      </div>
    </div>
  );
};

export default MainContent;
